#!/usr/bin/env node

import { mkdir, writeFile } from 'node:fs/promises';
import { dirname } from 'node:path';

const args = process.argv.slice(2);

function takeFlag(name) {
  const index = args.indexOf(name);
  if (index < 0) return undefined;
  const value = args[index + 1];
  if (!value || value.startsWith('--')) {
    throw new Error(`${name} requires a value`);
  }
  args.splice(index, 2);
  return value;
}

function takeAllFlags(name) {
  const values = [];
  for (;;) {
    const value = takeFlag(name);
    if (value === undefined) return values;
    values.push(value);
  }
}

function hasFlag(name) {
  const index = args.indexOf(name);
  if (index < 0) return false;
  args.splice(index, 1);
  return true;
}

const modelId = takeFlag('--model-id') ?? 'flux-1-schnell';
const base = takeFlag('--base') ?? 'https://edgework-web.taylorbuley.workers.dev/api/v1/r2/distributed-inference/models';
const expectedArtifact = takeFlag('--artifact') ?? `models/${modelId}.knot`;
const output = takeFlag('--output');
const failOnMissing = hasFlag('--fail-on-missing');
const keys = takeAllFlags('--key');

if (args.length > 0) {
  throw new Error(`unknown arguments: ${args.join(' ')}`);
}

const artifactKeys = keys.length > 0
  ? keys
  : [
      `${modelId}.knot`,
      `${modelId}.knot.manifest.json`,
      `${modelId}.knot.admission.json`,
    ];

const COMPONENT_POLICY = 'flux-with-vae-text-encoders';
const EXPECTED_INCLUDED = ['transformer', 'vae', 'text_encoder', 'text_encoder_2'];
const COMPONENT_PREFIXES = {
  transformer: ['flux_img_in_', 'flux_dbl_', 'flux_sgl_'],
  vae: ['flux_vae_'],
  text_encoder: ['flux_clip_'],
  text_encoder_2: ['flux_t5_'],
};
const MAX_SIDECAR_BYTES = 1024 * 1024;
const MAX_KNOT_HEADER_BYTES = 4 * 1024 * 1024;

function artifactUrl(key) {
  const normalizedKey = key.replace(/^\/+/, '');
  const encodedKey = normalizedKey.split('/').map(encodeURIComponent).join('/');
  return `${base.replace(/\/+$/, '')}/${encodedKey}`;
}

function positiveContentLength(value) {
  if (value === null) return false;
  const parsed = Number(value);
  return Number.isFinite(parsed) && parsed > 0;
}

async function headArtifact(key) {
  const url = artifactUrl(key);
  try {
    const response = await fetch(url, { method: 'HEAD' });
    const contentLength = response.headers.get('content-length');
    const errors = [];
    if (!response.ok) {
      errors.push(`http ${response.status}`);
    } else if (!positiveContentLength(contentLength)) {
      errors.push('missing or zero content-length');
    }
    return {
      key,
      url,
      ok: response.ok,
      status: response.status,
      contentLength,
      etag: response.headers.get('etag'),
      lastModified: response.headers.get('last-modified'),
      errors,
    };
  } catch (error) {
    return {
      key,
      url,
      ok: false,
      status: 0,
      error: error instanceof Error ? error.message : String(error),
      errors: [error instanceof Error ? error.message : String(error)],
    };
  }
}

function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function pushIf(errors, condition, message) {
  if (condition) errors.push(message);
}

function tensorCountsFromMetadata(metadata) {
  const tensors = isObject(metadata.tensors) ? metadata.tensors : {};
  return Object.fromEntries(Object.entries(COMPONENT_PREFIXES).map(([component, prefixes]) => [
    component,
    Object.keys(tensors).filter((name) => prefixes.some((prefix) => name.startsWith(prefix))).length,
  ]));
}

function validateFluxMetadata(metadata, errors) {
  const config = isObject(metadata.config) ? metadata.config : {};
  const components = isObject(metadata.components) ? metadata.components : {};
  const tensors = isObject(metadata.tensors) ? metadata.tensors : {};

  pushIf(errors, config.arch !== 'flux', 'KNOT metadata config.arch is not flux');
  pushIf(errors, components.policy !== COMPONENT_POLICY, `KNOT components.policy is not ${COMPONENT_POLICY}`);

  const included = Array.isArray(components.included) ? components.included : [];
  for (const component of EXPECTED_INCLUDED) {
    pushIf(errors, !included.includes(component), `KNOT components.included missing ${component}`);
  }

  for (const [component, prefixes] of Object.entries(COMPONENT_PREFIXES)) {
    const entries = Object.entries(tensors).filter(([name]) => prefixes.some((prefix) => name.startsWith(prefix)));
    const shaped = entries.filter(([, info]) => (
      isObject(info) && Array.isArray(info.shape) && info.shape.length > 0
    ));
    pushIf(errors, entries.length === 0, `KNOT missing ${component} tensors`);
    pushIf(
      errors,
      entries.length > 0 && entries.length !== shaped.length,
      `KNOT ${component} tensors missing shape metadata: ${entries.length - shaped.length} of ${entries.length}`,
    );
  }

  return tensorCountsFromMetadata(metadata);
}

function validateSidecarJson(key, json, errors, context) {
  if (!isObject(json)) {
    errors.push(`${key} is not a JSON object`);
    return;
  }

  pushIf(errors, json.model_id !== modelId, `${key} model_id is not ${modelId}`);
  pushIf(errors, json.artifact !== expectedArtifact, `${key} artifact is not ${expectedArtifact}`);
  pushIf(errors, json.arch !== 'flux', `${key} arch is not flux`);
  pushIf(errors, json.format !== 'knot/v1', `${key} format is not knot/v1`);
  pushIf(errors, typeof json.size !== 'number' || json.size <= 0, `${key} size is not positive`);
  pushIf(errors, typeof json.sha256 !== 'string' || !/^[a-f0-9]{64}$/i.test(json.sha256), `${key} sha256 is not a hex sha256`);

  const components = isObject(json.components) ? json.components : {};
  pushIf(errors, components.policy !== COMPONENT_POLICY, `${key} components.policy is not ${COMPONENT_POLICY}`);

  if (key.endsWith('.admission.json')) {
    pushIf(errors, json.status !== 'shape-admitted', `${key} status is not shape-admitted`);
    pushIf(errors, json.admission_level !== 'artifact-shape-only', `${key} admission_level is not artifact-shape-only`);
    pushIf(errors, json.visible_image_admitted !== false, `${key} visible_image_admitted is not false`);
    pushIf(errors, json.smoke_test_artifact !== false, `${key} smoke_test_artifact is not false`);
  }

  if (context.knotLength !== undefined) {
    pushIf(errors, json.size !== context.knotLength, `${key} size does not match remote KNOT content-length`);
  }

  if (context.knotTensorCounts !== undefined) {
    const sidecarCounts = isObject(json.tensor_counts) ? json.tensor_counts : {};
    for (const component of EXPECTED_INCLUDED) {
      pushIf(
        errors,
        sidecarCounts[component] !== context.knotTensorCounts[component],
        `${key} tensor_counts.${component} does not match remote KNOT header`,
      );
    }
  }
}

async function validateSidecar(artifact, context) {
  if (!artifact.ok) return;
  try {
    const response = await fetch(artifact.url);
    if (!response.ok) {
      artifact.errors.push(`GET ${response.status}`);
      return;
    }
    const contentLength = response.headers.get('content-length');
    if (contentLength !== null && Number(contentLength) > MAX_SIDECAR_BYTES) {
      artifact.errors.push(`sidecar too large: ${contentLength} bytes`);
      return;
    }
    const json = await response.json();
    validateSidecarJson(artifact.key, json, artifact.errors, context);
  } catch (error) {
    artifact.errors.push(`sidecar validation failed: ${error instanceof Error ? error.message : String(error)}`);
  }
}

async function validateKnotHeader(artifact, context) {
  if (!artifact.ok) return undefined;
  try {
    const response = await fetch(artifact.url, {
      headers: {
        Range: `bytes=0-${MAX_KNOT_HEADER_BYTES - 1}`,
      },
    });
    if (!response.ok) {
      artifact.errors.push(`range GET ${response.status}`);
      return;
    }
    if (response.status !== 206) {
      const contentLength = response.headers.get('content-length');
      if (!positiveContentLength(contentLength) || Number(contentLength) > MAX_KNOT_HEADER_BYTES) {
        artifact.errors.push('server did not honor Range for large KNOT header check');
        return;
      }
    }

    const bytes = new Uint8Array(await response.arrayBuffer());
    if (bytes.length < 10) {
      artifact.errors.push('KNOT header shorter than 10 bytes');
      return;
    }
    const magic = new TextDecoder().decode(bytes.slice(0, 4));
    if (magic !== 'KNOT') {
      artifact.errors.push(`bad KNOT magic: ${magic}`);
      return;
    }
    const view = new DataView(bytes.buffer, bytes.byteOffset, bytes.byteLength);
    const metadataLength = view.getUint32(6, true);
    if (metadataLength <= 0 || metadataLength > MAX_KNOT_HEADER_BYTES) {
      artifact.errors.push(`implausible KNOT metadata length: ${metadataLength}`);
      return;
    }
    if (bytes.length < 10 + metadataLength) {
      artifact.errors.push(`KNOT metadata exceeds fetched header: ${metadataLength} bytes`);
      return;
    }
    const metadataText = new TextDecoder().decode(bytes.slice(10, 10 + metadataLength));
    const metadata = JSON.parse(metadataText);
    const counts = validateFluxMetadata(metadata, artifact.errors);
    context.knotTensorCounts = counts;
    const length = Number(artifact.contentLength);
    if (Number.isFinite(length) && length > 0) {
      context.knotLength = length;
    }
    return metadata;
  } catch (error) {
    artifact.errors.push(`KNOT header validation failed: ${error instanceof Error ? error.message : String(error)}`);
  }
  return undefined;
}

const artifacts = [];
const context = {};
for (const key of artifactKeys) {
  const artifact = await headArtifact(key);
  artifacts.push(artifact);
}

for (const artifact of artifacts.filter((item) => item.key.endsWith('.knot'))) {
  await validateKnotHeader(artifact, context);
}
for (const artifact of artifacts.filter((item) => item.key.endsWith('.json'))) {
  await validateSidecar(artifact, context);
}

const missing = artifacts.filter((artifact) => !artifact.ok);
const invalid = artifacts.filter((artifact) => artifact.ok && artifact.errors.length > 0);
const report = {
  modelId,
  checkedAt: new Date().toISOString(),
  base,
  expectedArtifact,
  status: missing.length > 0 ? 'missing' : invalid.length > 0 ? 'invalid' : 'present',
  artifacts,
  blocker: missing.length === 0 && invalid.length === 0
    ? null
    : {
        kind: missing.length > 0 ? 'artifact-missing' : 'artifact-invalid',
        missingKeys: missing.map((artifact) => artifact.key),
        invalidKeys: invalid.map((artifact) => artifact.key),
        nextTargets: [
          'distributed-inference:preflight-flux-schnell-knot',
          'distributed-inference:build-flux-schnell-knot',
          'distributed-inference:encode-flux-schnell-knot',
          'distributed-inference:write-flux-schnell-sidecars',
          'distributed-inference:probe-flux-schnell-knot',
          'distributed-inference:upload-flux-schnell-knot',
          'distributed-inference:assert-flux-schnell-knot',
          'distributed-inference:operationalize-flux-schnell-knot',
        ],
      },
};

for (const artifact of artifacts) {
  const length = artifact.contentLength ? ` bytes=${artifact.contentLength}` : '';
  const error = artifact.error ? ` error=${artifact.error}` : '';
  const errors = artifact.errors.length > 0 ? ` invalid=${artifact.errors.join('; ')}` : '';
  console.log(`${artifact.key} ${artifact.status}${length}${error}${errors}`);
}

if (output) {
  await mkdir(dirname(output), { recursive: true });
  await writeFile(output, `${JSON.stringify(report, null, 2)}\n`);
  console.log(`wrote ${output}`);
}

if (failOnMissing && (missing.length > 0 || invalid.length > 0)) {
  console.error(`missing=${missing.length} invalid=${invalid.length} total=${artifacts.length} ${modelId} artifacts`);
  process.exitCode = 2;
}
